const fs = require('fs');
const path = require('path');

describe('cleanup orphaned test files', () => {
  test('delete all orphaned files', () => {
    const filesToDelete = [
      'estudio_ia_videos/src/app/test-pptx-api.js',
      'estudio_ia_videos/src/app/test-nr12-brazilian-content.js',
      'estudio_ia_videos/src/app/test-pptx-simple.js',
      'estudio_ia_videos/src/app/test-render.js',
      'estudio_ia_videos/src/app/test-websocket.js',
      'estudio_ia_videos/src/app/test-pptx-complete.js',
      'estudio_ia_videos/src/app/test-simple.js',
      'estudio_ia_videos/src/app/test-runner.js',
      'estudio_ia_videos/src/app/test-real-pptx-processing.js',
      'estudio_ia_videos/src/app/test-render-system.js',
      'estudio_ia_videos/src/app/test-pptx-endpoint.js',
      'estudio_ia_videos/src/app/test-pptx-processor-direct.js',
      'estudio_ia_videos/src/lib/harness/mocks.ts',
      'estudio_ia_videos/src/app/jest.websocket.setup.ts',
      'estudio_ia_videos/test-state.json',
      'estudio_ia_videos/test_output.txt',
      'estudio_ia_videos/test_output_v2.txt',
      'estudio_ia_videos/test_output_v3.txt',
      'estudio_ia_videos/test_output_v4.txt',
      'estudio_ia_videos/test_output_v5.txt',
      'estudio_ia_videos/test_output_v6.txt',
      'estudio_ia_videos/test-pptx.ts',
      'estudio_ia_videos/stryker.conf.mjs',
      'estudio_ia_videos/artillery.yml',
      'pytest.ini',
    ];

    const root = '/root/_MVP_Video_TecnicoCursos_v7';
    const results = [];

    for (const f of filesToDelete) {
      const full = path.join(root, f);
      try {
        if (fs.existsSync(full)) {
          fs.unlinkSync(full);
          results.push(`DELETED: ${f}`);
        } else {
          results.push(`NOT_FOUND: ${f}`);
        }
      } catch (e) {
        results.push(`ERROR: ${f} - ${e.message}`);
      }
    }

    // Try to remove empty harness directory
    const harnessDir = path.join(root, 'estudio_ia_videos/src/lib/harness');
    try {
      if (fs.existsSync(harnessDir)) {
        fs.rmdirSync(harnessDir);
        results.push('DELETED_DIR: estudio_ia_videos/src/lib/harness/');
      }
    } catch (e) {
      results.push(`HARNESS_DIR: ${e.message}`);
    }

    console.log(results.join('\n'));
    
    // Verify all files are gone
    for (const f of filesToDelete) {
      const full = path.join(root, f);
      expect(fs.existsSync(full)).toBe(false);
    }
  });
});
